SmartRisk.Sidebar={init(){const e=document.getElementById("app-sidebar");e.innerHTML=`<div class="sidebar-brand"><div class="sidebar-brand-mark">SR</div><div class="sidebar-brand-copy"><h1 class="sidebar-brand-title">SmartRisk CZ5</h1><p class="sidebar-brand-subtitle">Gestión territorial del riesgo</p></div></div><nav class="sidebar-nav">${SmartRisk.Config.navigation.map(i=>`<a class="sidebar-link" data-route="${i.path}" href="#${i.path}"><span class="sidebar-link-icon">${SmartRisk.Icon.render(i.icon,20)}</span><span class="sidebar-link-label">${i.label}</span></a>`).join("")}</nav><div class="sidebar-footer"><div class="sidebar-footer-copy">${SmartRisk.Constants.APP_VERSION}</div></div>`},toggle(){const e=document.getElementById("app-sidebar");if(innerWidth<=860)e.classList.toggle("is-mobile-open");else e.classList.toggle("is-collapsed")},setActive(p){document.querySelectorAll(".sidebar-link").forEach(a=>a.classList.toggle("is-active",a.dataset.route===p))}};